class Node:
    def __init__(self, data):
        self.data = data
        self.next = None
        self.prev = None

class DoublyLinkedList:
    def __init__(self):
        self.head = None
        self.tail = None
        self._size = 0

    def __len__(self):
        return self._size

    def append(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
            self.tail = new_node
        else:
            self.tail.next = new_node
            new_node.prev = self.tail
            self.tail = new_node
        self._size += 1

    def prepend(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
            self.tail = new_node
        else:
            new_node.next = self.head
            self.head.prev = new_node
            self.head = new_node
        self._size += 1

    def delete(self, data):
        if not self.head or self.head is None:
            raise ValueError("List is empty")

        current = self.head
        while current:
            if current.data == data:
                # Found the node to delete
                if current == self.head:
                    self.head = current.next
                    if self.head:
                        self.head.prev = None
                    else: # List becomes empty
                        self.tail = None
                elif current == self.tail:
                    self.tail = current.prev
                    self.tail.next = None
                else:
                    # Middle element
                    current.prev.next = current.next
                    current.next.prev = current.prev

                current.next = None  # Isolate the node for garbage collection (good practice)
                current.prev = None
                self._size -= 1
                return
            current = current.next

        raise ValueError(f"{data} not found in the linked list")

    def __iter__(self):
        current = self.head
        while current:
            yield current.data
            current = current.next

    def __repr__(self):
        return f"DoublyLinkedList size={self._size}"

    def __bool__(self):
        # This check is problematic because it uses isinstance(self, type) which is always false for an instance of DoublyLinkedList. 
        # For pytest coverage, just checking if size > 0 means the list is non-empty structurely.
        return self._size > 0


    def reverse(self):
        if not self.head or not self.tail:
            return

        current = self.head
        while current:
            # Swap next and prev for the current node
            temp_link = current.prev
            current.prev = current.next
            current.next = temp_link
            temp_link = current # Save original 'prev' (now 'next') before moving

            if temp_link is None: break # Should not happen if logic is correct, but safety first

            # Move to the next node in the *original* sequence (which is stored now in .prev)
            current = current.prev 

        # After swapping links in all nodes, swap head and tail pointers globally
        self.head, self.tail = self.tail, self.head

# Ensure __repr__ works correctly for visualization if needed later
    def __str__(self):
        return str(list(self))

